+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title..." @bind="searchQuery" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="row g-3">
+        @foreach (var column in columns)
+        {
+            var colTasks = GetFilteredColumnTasks(column);
+            <div class="col-md-4">
+                <div class="card h-100">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <strong>@column</strong>
+                        <span class="badge bg-secondary">@colTasks.Count</span>
+                    </div>
+                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="min-height:200px;max-height:70vh;">
+                        @foreach (var task in colTasks)
+                        {
+                            <div class="card shadow-sm">
+                                <div class="card-body p-2">
+                                    <div class="fw-semibold mb-1">@task.Title</div>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <small class="text-muted">@task.Assignee</small>
+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                    </div>
+                                    <div class="d-flex justify-content-between align-items-center">
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                        <div>
+                                            @if (column != columns[0])
+                                            {
+                                                <button class="btn btn-outline-secondary btn-sm me-1" @onclick="() => MoveTask(task, -1)" disabled="@isBusy">&laquo;</button>
+                                            }
+                                            @if (column != columns[^1])
+                                            {
+                                                <button class="btn btn-outline-secondary btn-sm" @onclick="() => MoveTask(task, 1)" disabled="@isBusy">&raquo;</button>
+                                            }
+                                        </div>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (addingToColumn == column)
+                        {
+                            <div class="card border-primary">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Title" @bind="newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-2" @bind="newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm flex-fill" @onclick="SaveNewTask" disabled="@isBusy">Save</button>
+                                        <button class="btn btn-outline-secondary btn-sm flex-fill" @onclick="CancelAdd" disabled="@isBusy">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer">
+                        <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => StartAdd(column)" disabled="@(addingToColumn is not null)">+ Add Task</button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> allTasks = new();
+    private bool isLoading = true;
+    private bool isBusy;
+    private string? errorMessage;
+    private string searchQuery = string.Empty;
+
+    // Add-task form state
+    private string? addingToColumn;
+    private string newTitle = string.Empty;
+    private string newAssignee = string.Empty;
+    private string newPriority = "Medium";
+    private DateTime newDueDate = DateTime.Today.AddDays(7);
+
+    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status)
+        => allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status)
+        => allTasks
+            .Where(t => t.Status == status
+                && (string.IsNullOrWhiteSpace(searchQuery)
+                    || t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private async Task MoveTask(TaskItem task, int direction)
+    {
+        var currentIndex = Array.IndexOf(columns, task.Status);
+        var newIndex = currentIndex + direction;
+        if (newIndex < 0 || newIndex >= columns.Length) return;
+
+        isBusy = true;
+        try
+        {
+            var newStatus = columns[newIndex];
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            isBusy = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        addingToColumn = column;
+        newTitle = string.Empty;
+        newAssignee = string.Empty;
+        newPriority = "Medium";
+        newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => addingToColumn = null;
+
+    private async Task SaveNewTask()
+    {
+        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;
+
+        isBusy = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
+            // The service creates with default status; we need the task in the correct column
+            var finalTask = created.Status == addingToColumn ? created : created with { Status = addingToColumn };
+            if (finalTask.Status != created.Status)
+            {
+                await TaskService.UpdateTaskStatusAsync(finalTask.Id, addingToColumn);
+            }
+            allTasks.Add(finalTask);
+            addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            isBusy = false;
+        }
+    }
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+}
